// Ambil body dari request
const body = $input.first().json.body || {};
const topik = body.topik || "";
let regenerate = body.regenerate || null;

// Validasi nilai regenerate → hanya boleh visual, auditori, kinestetik, penjelasan
const allowed = ["visual", "auditori", "kinestetik", "penjelasan"];
if (regenerate && !allowed.includes(regenerate)) {
  throw new Error(`Invalid regenerate value: ${regenerate}. Harus salah satu dari ${allowed.join(", ")}`);
}

// Buat instruksi prompt untuk AI
let promptText = "";

if (regenerate) {
  promptText = `Topik: ${topik}.
Hasilkan ulang hanya bagian ${regenerate}.
Bagian lain kosong ("").
Jawab HANYA dalam JSON.`;
} else {
  promptText = `Topik: ${topik}.
Buatkan materi belajar lengkap dengan 3 gaya belajar:
- visual (URL ilustrasi/diagram)
- auditori (URL video)
- kinestetik (langkah praktik singkat)
- penjelasan (ringkas dan jelas)
Jawab HANYA dalam JSON.`;
}

// Hapus newline agar prompt jadi 1 baris
promptText = promptText.replace(/\\n/g, " ");

// Kirim ke AI Agent lewat output json
return [
  {
    json: {
      prompt: promptText,
      topik,
      regenerate
    }
  }
];

const rawOutput = $input.first().json.output || "";

// Bersihkan pembungkus markdown (```json ... ```)
let cleaned = rawOutput
  .replace(/```json/g, '')   // hapus pembuka ```json
  .replace(/```/g, '')       // hapus penutup ```
  .trim();                   // hapus spasi/line break berlebih

// Parse ke JSON
let parsed;
try {
  parsed = JSON.parse(cleaned);
} catch (err) {
  throw new Error("Gagal parse JSON dari AI Agent: " + err.message + "\nHasil cleaned: " + cleaned);
}

return [
  {
    json: parsed
  }
];
